    }

    [Fact]
    public void RoundtripJson()
    {
        // Test that FromJson -> ToJson -> FromJson produces equivalent data
        string jsonData = """
{
  "name": "get_weather",
  "description": "Get the current weather for a city"
}
""";

        var original = AnthropicToolDefinition.FromJson(jsonData);
        Assert.NotNull(original);

        var json = original.ToJson();
        Assert.False(string.IsNullOrEmpty(json));

        var reloaded = AnthropicToolDefinition.FromJson(json);
        Assert.NotNull(reloaded);
        Assert.Equal("get_weather", reloaded.Name);
        Assert.Equal("Get the current weather for a city", reloaded.Description);
    }

